    def _default_name_fallback_for_prefab(self, body: Optional[Dict[str, Any]]) -> str:
        """Default filename stub when the name field is empty."""
        if not body:
            return "object"
        t = body.get("type", "planet")
        if t == "star":
            return "star"
        if t == "moon":
            return "moon"
        return "planet"

    def _save_prefab_modal_title(self) -> str:
        """Modal heading: star / planet / moon."""
        bid = getattr(self, "save_prefab_target_body_id", None)
        body = self.bodies_by_id.get(bid) if bid else self.selected_body
        t = (body or {}).get("type", "planet")
        if t == "star":
            return "Save as a star preset"
        if t == "moon":
            return "Save as a moon preset"
        return "Save as a planet preset"

    def _try_commit_save_prefab(self) -> None:
        """Write object_library prefab from modal (star, planet, or moon)."""
        if not PERSISTENCE_AVAILABLE:
            return
        body = (
            self.bodies_by_id.get(getattr(self, "save_prefab_target_body_id", None))
            if getattr(self, "save_prefab_target_body_id", None)
            else self.selected_body
        )
        fb = self._default_name_fallback_for_prefab(body)
        name = (getattr(self, "save_prefab_name_text", "") or fb).strip()
        if not name or not body or body.get("type") not in ("star", "planet", "moon"):
            return
        try:
            to_save = dict(body)
            to_save["name"] = name
            to_save["display_name"] = name
            path = save_object_prefab(to_save)
            self._show_export_toast(path)
        except Exception as e:
            print(f"Save prefab failed: {e}")

