    def draw_scale_indicator(self):
        """Draw a compact zoom-aware distance scale indicator in the bottom-left corner (same width as time panel)."""
        layout = self._get_time_controls_layout()
        bg_rect = layout["scale_indicator_rect"]
        fixed_box_width = bg_rect.width
        fixed_box_height = bg_rect.height
        box_x = bg_rect.left
        max_bar_width = fixed_box_width - 24
        x_start = box_x + 10
        y_pos = bg_rect.centery
        
        # Calculate pixels per AU at current zoom
        pixels_per_au = self.scale * self.camera.zoom
        target_min = 60
        target_max = min(100, max_bar_width - 40)
        candidate_scales = []
        for i in range(-5, 6):
            base = 10**i
            candidate_scales.extend([base, base * 2, base * 5])
        candidate_scales.sort()
        selected_au = candidate_scales[0]
        for au in candidate_scales:
            width_px = au * pixels_per_au
            if width_px >= target_min:
                selected_au = au
                if width_px > target_max:
                    prev_au = candidate_scales[max(0, candidate_scales.index(au)-1)]
                    prev_width = prev_au * pixels_per_au
                    target_mid = (target_min + target_max) / 2
                    if abs(prev_width - target_mid) < abs(width_px - target_mid):
                        selected_au = prev_au
                break
            selected_au = au
        width_px = selected_au * pixels_per_au
        display_width_px = min(width_px, max_bar_width)
        
        if selected_au >= 1000:
            label_text = f"{selected_au:,.0f} AU"
        elif selected_au >= 1:
            label_text = f"{selected_au:g} AU"
        else:
            label_text = f"{selected_au:g} AU"
        tick_height = 4
        label_surface = self.tiny_font.render(label_text, True, (200, 205, 215))
        label_rect = label_surface.get_rect(midleft=(x_start + display_width_px + 8, y_pos))
        
        # Draw background box (same width as time panel)
        bg_surface = pygame.Surface(bg_rect.size, pygame.SRCALPHA)
        bg_surface.fill((20, 25, 35, 180))
        self.screen.blit(bg_surface, bg_rect.topleft)
        pygame.draw.rect(self.screen, (60, 70, 90), bg_rect, 1, border_radius=4)
        
        # Draw scale bar
        line_color = (180, 185, 195)
        pygame.draw.line(self.screen, line_color, (x_start, y_pos), (x_start + display_width_px, y_pos), 1)
        pygame.draw.line(self.screen, line_color, (x_start, y_pos - tick_height), (x_start, y_pos + tick_height), 1)
        pygame.draw.line(self.screen, line_color, (x_start + display_width_px, y_pos - tick_height), (x_start + display_width_px, y_pos + tick_height), 1)
        self.screen.blit(label_surface, label_rect)
        
        self._scale_indicator_height = bg_rect.height + 4
    
    def _draw_scale_on_surface(self, surface: pygame.Surface, viewport_width: int, viewport_height: int):
        """Draw the zoom-aware distance scale at bottom-left of the given surface (for export)."""
        pixels_per_au = self.scale * self.camera.zoom
        target_min = 80
        target_max = 120
        candidate_scales = []
        for i in range(-5, 6):
            base = 10**i
            candidate_scales.extend([base, base * 2, base * 5])
        candidate_scales.sort()
        selected_au = candidate_scales[0]
        for au in candidate_scales:
            width_px = au * pixels_per_au
            if width_px >= target_min:
                selected_au = au
                if width_px > target_max:
                    prev_au = candidate_scales[max(0, candidate_scales.index(au)-1)]
                    prev_width = prev_au * pixels_per_au
                    target_mid = (target_min + target_max) / 2
                    if abs(prev_width - target_mid) < abs(width_px - target_mid):
                        selected_au = prev_au
                break
            selected_au = au
        width_px = selected_au * pixels_per_au
        margin_x = 25
        margin_y = 25
        y_pos = viewport_height - margin_y - 45
        x_start = margin_x
        if selected_au >= 1000:
            label_text = f"{selected_au:,.0f} AU"
        elif selected_au >= 1:
            label_text = f"{selected_au:g} AU"
        else:
            label_text = f"{selected_au:g} AU"
        tick_height = 6
        label_surface = self.subtitle_font.render(label_text, True, self.WHITE)
        label_rect = label_surface.get_rect(midtop=(x_start + width_px/2, y_pos + tick_height + 4))
        bg_rect = label_rect.inflate(16, 8)
        scale_rect = pygame.Rect(x_start - 8, y_pos - tick_height - 4, width_px + 16, tick_height * 2 + 8)
        bg_rect = bg_rect.union(scale_rect)
        bg_surface = pygame.Surface(bg_rect.size, pygame.SRCALPHA)
        bg_surface.fill((0, 0, 0, 140))
        surface.blit(bg_surface, bg_rect.topleft)
        line_color = self.WHITE
        line_thickness = 2
        pygame.draw.line(surface, line_color, (x_start, y_pos), (x_start + width_px, y_pos), line_thickness)
        pygame.draw.line(surface, line_color, (x_start, y_pos - tick_height), (x_start, y_pos + tick_height), line_thickness)
        pygame.draw.line(surface, line_color, (x_start + width_px, y_pos - tick_height), (x_start + width_px, y_pos + tick_height), line_thickness)
        surface.blit(label_surface, label_rect)
    
