                                    self.luminosity_dropdown_selected = "G-dwarf (Sun)"
                                    self.radius_dropdown_selected = "G-type (Sun)"
                                    self.activity_dropdown_selected = "Moderate (Sun)"
                                    self.metallicity_dropdown_selected = "0.0 (Sun)"
